{
  "grammar": [
    {
      "pattern": "要 + Verb + 完",
      "structure": ["要", "Verb", "完"],
      "explanation_en": "Use '要 + Verb + 完' to express that something must be completed by a certain time or deadline. It emphasizes the necessity of finishing an action.",
      "title": "Expressing 'Must Finish' with 要 + Verb + 完",
      "meaning": "Must finish (Verb)ing",
      "when_to_use": ["When talking about deadlines or tasks that need to be completed", "When emphasizing the necessity of finishing an action"],
      "when_not_to_use": ["When the action is not about completion", "When you want to express a general desire without a deadline"],
      "pragmatic_notes": "In Taiwan, this structure is very common in workplace settings, especially when discussing project deadlines or homework. It sounds direct and clear, so it's appropriate for professional contexts.",
      "word_order_notes": "The structure is '要 + Verb + 完'. The verb must be placed before '完', and '完' indicates the completion of the action.",
      "english_contrast": "In English, you might say 'must finish' or 'need to complete'. The Chinese structure places '要' (must) before the verb, and '完' (finish) after the verb.",
      "korean_contrast": "In Korean, you might use '-어야 하다' or '-아야 하다' to express necessity. The Chinese structure is more direct with '要'.",
      "negative_examples": [
        {
          "text": "我要完做報告。",
          "error": "The verb must come before '完'. Correct order: '我要做完報告。'"
        }
      ],
      "incorrect_examples": [
        {
          "text": "我要完做報告。",
          "error": "The verb must come before '完'. Correct order: '我要做完報告。'"
        }
      ],
      "transformation_drills": ["Change '我要寫報告' to '我要寫完報告' to emphasize completion.", "Change '他要看書' to '他要看完書' to emphasize finishing the book."],
      "production_drills": ["Say that you must finish the report by Friday.", "Say that the team must finish the project before the deadline."],
      "common_error_patterns": ["Placing '完' before the verb instead of after", "Using '要' without a verb"],
      "repair_feedback": {
        "word_order": "Remember: '要' comes first, then the verb, then '完'.",
        "politeness": "This structure is neutral and can be used in both formal and informal settings.",
        "vocabulary": "Use verbs that indicate an action that can be completed, like '做' (do), '寫' (write), '看' (read)."
      }
    },
    {
      "pattern": "在 + Verb + 開會 / 討論",
      "structure": ["在", "Verb", "Object"],
      "explanation_en": "Use '在 + Verb + Object' to indicate an action that is currently in progress. This is the present continuous tense in Chinese.",
      "title": "Present Continuous with 在",
      "meaning": "Currently (Verb)ing",
      "when_to_use": ["When describing an action happening right now", "When talking about ongoing activities like meetings or discussions"],
      "when_not_to_use": ["When the action is completed or habitual", "When describing future plans without current action"],
      "pragmatic_notes": "In Taiwan, this structure is very common in both spoken and written Chinese. It's used to describe what someone is doing at the moment, especially in workplace contexts like '在開會' (in a meeting) or '在討論' (discussing).",
      "word_order_notes": "The structure is '在 + Verb + Object'. '在' is placed before the verb to indicate ongoing action.",
      "english_contrast": "In English, you use 'am/is/are + Verb-ing'. In Chinese, '在' serves a similar function but is placed before the verb.",
      "korean_contrast": "In Korean, you use '-고 있다' to indicate ongoing action. The Chinese structure is simpler with just '在' before the verb.",
      "negative_examples": [
        {
          "text": "我在開會現在。",
          "error": "The word order is correct, but '現在' (now) is usually placed at the beginning or after the subject for clarity. Better: '我現在在開會。'"
        }
      ],
      "incorrect_examples": [
        {
          "text": "我在開會現在。",
          "error": "The word order is correct, but '現在' (now) is usually placed at the beginning or after the subject for clarity. Better: '我現在在開會。'"
        }
      ],
      "transformation_drills": ["Change '他開會' to '他在開會' to indicate ongoing action.", "Change '我們討論' to '我們在討論' to indicate ongoing discussion."],
      "production_drills": ["Say that you are currently in a meeting.", "Say that the team is discussing the project."],
      "common_error_patterns": ["Forgetting to use '在' before the verb", "Using '在' with stative verbs like '是' or '有'"],
      "repair_feedback": {
        "word_order": "Remember: '在' comes before the verb to indicate ongoing action.",
        "politeness": "This structure is neutral and can be used in both formal and informal settings.",
        "vocabulary": "Use action verbs like '開會' (have a meeting), '討論' (discuss), '做' (do), '寫' (write)."
      }
    },
    {
      "pattern": "還沒 + Verb + 完",
      "structure": ["還沒", "Verb", "完"],
      "explanation_en": "Use '還沒 + Verb + 完' to express that an action has not yet been completed. It emphasizes that the action is still ongoing or not finished.",
      "title": "Expressing 'Not Yet Finished' with 還沒 + Verb + 完",
      "meaning": "Haven't finished (Verb)ing yet",
      "when_to_use": ["When talking about tasks or actions that are not yet complete", "When responding to questions about progress or deadlines"],
      "when_not_to_use": ["When the action is completed", "When you want to express that you have never done something (use '從來沒有')"],
      "pragmatic_notes": "In Taiwan, this structure is very common in workplace and school settings. It's a polite way to indicate that you are still working on something without sounding defensive.",
      "word_order_notes": "The structure is '還沒 + Verb + 完'. '還沒' is placed before the verb, and '完' after the verb to indicate completion.",
      "english_contrast": "In English, you might say 'haven't finished yet' or 'not done yet'. The Chinese structure places '還沒' (not yet) before the verb and '完' (finish) after.",
      "korean_contrast": "In Korean, you might use '아직 안 -었/았다' to express 'not yet finished'. The Chinese structure is similar with '還沒' before the verb.",
      "negative_examples": [
        {
          "text": "我還沒完做報告。",
          "error": "The verb must come before '完'. Correct order: '我還沒做完報告。'"
        }
      ],
      "incorrect_examples": [
        {
          "text": "我還沒完做報告。",
          "error": "The verb must come before '完'. Correct order: '我還沒做完報告。'"
        }
      ],
      "transformation_drills": ["Change '我做完報告' to '我還沒做完報告' to indicate not yet finished.", "Change '他看完書' to '他還沒看完書' to indicate not yet finished reading."],
      "production_drills": ["Say that you haven't finished the report yet.", "Say that the meeting hasn't ended yet."],
      "common_error_patterns": ["Placing '完' before the verb instead of after", "Using '還沒' without a verb"],
      "repair_feedback": {
        "word_order": "Remember: '還沒' comes first, then the verb, then '完'.",
        "politeness": "This structure is neutral and can be used in both formal and informal settings.",
        "vocabulary": "Use verbs that indicate an action that can be completed, like '做' (do), '寫' (write), '看' (read)."
      }
    }
  ]
}
